from flask import Flask
from flask_graphql import GraphQLView
import graphene

# Mock Product data
products = [
    {"id": "1", "name": "Product 1", "category": "Category 1", "price": 100.0},
    {"id": "2", "name": "Product 2", "category": "Category 2", "price": 150.0},
]

# Mock Category data
categories = ["Category 1", "Category 2"]

# Mock User Review data
user_reviews = [
    {"product_id": "1", "user": "User 1", "rating": 5, "review": "Great product!"},
    {"product_id": "1", "user": "User 2", "rating": 4, "review": "Good value for money."},
]

class Product(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    category = graphene.String()
    price = graphene.Float()

class Category(graphene.ObjectType):
    name = graphene.String()

class UserReview(graphene.ObjectType):
    product_id = graphene.ID()
    user = graphene.String()
    rating = graphene.Int()
    review = graphene.String()

class Query(graphene.ObjectType):
    products = graphene.List(Product)
    categories = graphene.List(Category)
    user_reviews = graphene.List(UserReview)

    def resolve_products(self, info):
        return products

    def resolve_categories(self, info):
        return categories

    def resolve_user_reviews(self, info):
        return user_reviews

schema = graphene.Schema(query=Query)

app = Flask(__name__)
app.add_url_rule('/graphql', view_func=GraphQLView.as_view('graphql', schema=schema, graphiql=True))
app.run()